	"FEHLER_CODE" NUMBER(*,5), 
	"FEHLER_TEXT" VARCHAR2(2500 CHAR), 
	"CREATED_DATE" DATE DEFAULT sysdate NOT NULL ENABLE, 
	"CREATED_LOGIN_ID" NUMBER(*,0) DEFAULT -1 NOT NULL ENABLE, 
	"LAST_CHANGE_DATE" DATE, 
	"LAST_CHANGE_LOGIN_ID" NUMBER(*,0)
   ) ;
ALTER TABLE "DIRKSPZM32"."S_QS_STATUS" ADD CONSTRAINT "CHECK_S_QS_STATUS_STATUS" CHECK (status in ('N','U','UE','ERR')) ENABLE;
ALTER TABLE "DIRKSPZM32"."S_QS_STATUS" ADD CONSTRAINT "PK_S_QS_STATUS" PRIMARY KEY ("LTE_ID", "CREATED_DATE")
  USING INDEX  ENABLE;


